// ── COMPONENTES BASE ─────────────────────────────────────────
const Btn = ({ onClick, children, variant='primary', small, style={} }) => {
  const base = { border:'none', cursor:'pointer', fontFamily:'inherit', fontWeight:600, borderRadius:6, transition:'opacity .15s', display:'inline-flex', alignItems:'center', gap:6, letterSpacing:.3 };
  const sizes = small ? { padding:'5px 12px', fontSize:12 } : { padding:'9px 18px', fontSize:13 };
  const variants = {
    primary: { background: C.gold, color:'#fff' },
    outline: { background:'transparent', border:`1.5px solid ${C.gold}`, color: C.gold },
    ghost:   { background:'transparent', border:`1px solid ${C.border}`, color: C.textMid },
    danger:  { background: C.red, color:'#fff' },
    success: { background: C.green, color:'#fff' },
  };
  return <button onClick={onClick} style={{...base,...sizes,...variants[variant],...style}} onMouseOver={e=>e.currentTarget.style.opacity='.82'} onMouseOut={e=>e.currentTarget.style.opacity='1'}>{children}</button>;
};

const Inp = ({ label, value, onChange, type='text', placeholder='', style={} }) => (
  <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
    {label && <label style={{ fontSize:11, fontWeight:600, color: C.textMid, textTransform:'uppercase', letterSpacing:.5 }}>{label}</label>}
    <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{ padding:'8px 10px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:13, color: C.text, background:'#fff', outline:'none', ...style }}
      onFocus={e=>e.target.style.borderColor=C.gold} onBlur={e=>e.target.style.borderColor=C.border} />
  </div>
);

const Sel = ({ label, value, onChange, opts, style={} }) => (
  <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
    {label && <label style={{ fontSize:11, fontWeight:600, color: C.textMid, textTransform:'uppercase', letterSpacing:.5 }}>{label}</label>}
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{ padding:'8px 10px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:13, color: C.text, background:'#fff', outline:'none', ...style }}
      onFocus={e=>e.target.style.borderColor=C.gold} onBlur={e=>e.target.style.borderColor=C.border}>
      {opts.map(o => <option key={o.value||o} value={o.value||o}>{o.label||o}</option>)}
    </select>
  </div>
);

const Txt = ({ label, value, onChange, rows=3, placeholder='', style={} }) => (
  <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
    {label && <label style={{ fontSize:11, fontWeight:600, color: C.textMid, textTransform:'uppercase', letterSpacing:.5 }}>{label}</label>}
    <textarea rows={rows} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{ padding:'8px 10px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:13, color: C.text, background:'#fff', outline:'none', resize:'vertical', fontFamily:'inherit', ...style }}
      onFocus={e=>e.target.style.borderColor=C.gold} onBlur={e=>e.target.style.borderColor=C.border} />
  </div>
);

const Card = ({ children, style={}, onClick }) => (
  <div onClick={onClick} style={{ background: C.card, border:`1px solid ${C.border}`, borderRadius:10, padding:16, boxShadow: C.shadow, cursor: onClick?'pointer':'default', ...style }}
    onMouseOver={e=>onClick&&(e.currentTarget.style.boxShadow=C.shadowMd)} onMouseOut={e=>onClick&&(e.currentTarget.style.boxShadow=C.shadow)}>
    {children}
  </div>
);

const Tag = ({ label, cor, corPale, small }) => (
  <span style={{ background: corPale||C.goldPale, color: cor||C.gold, borderRadius:20, padding: small?'2px 8px':'3px 10px', fontSize: small?10:11, fontWeight:700, letterSpacing:.4, whiteSpace:'nowrap' }}>{label}</span>
);

const Modal = ({ title, onClose, children, wide }) => (
  <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.45)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000, padding:20 }}>
    <div style={{ background:'#fff', borderRadius:12, padding:28, width:'100%', maxWidth: wide?900:560, maxHeight:'90vh', overflowY:'auto', boxShadow:'0 8px 40px rgba(0,0,0,.18)' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20, borderBottom:`1px solid ${C.border}`, paddingBottom:14 }}>
        <h2 style={{ margin:0, fontSize:17, color: C.text, fontWeight:700 }}>{title}</h2>
        <button onClick={onClose} style={{ border:'none', background:'none', fontSize:20, cursor:'pointer', color: C.textLight }}>x</button>
      </div>
      {children}
    </div>
  </div>
);

const Tabs = ({ tabs, active, onChange }) => (
  <div style={{ display:'flex', gap:4, borderBottom:`2px solid ${C.border}`, marginBottom:20, flexWrap:'wrap' }}>
    {tabs.map(t => (
      <button key={t} onClick={()=>onChange(t)} style={{ padding:'8px 16px', border:'none', background:'none', fontSize:13, cursor:'pointer', fontWeight: active===t?700:500, color: active===t? C.gold : C.textMid, borderBottom: active===t?`2px solid ${C.gold}`:'2px solid transparent', marginBottom:-2, fontFamily:'inherit', transition:'color .15s' }}>{t}</button>
    ))}
  </div>
);

const StatusBadge = ({ status }) => {
  const f = fluxoObj(status);
  return <Tag label={fluxoLabel(status)} cor={f.cor} corPale={f.corPale} />;
};

// ── UTILITÁRIOS ──────────────────────────────────────────────
const moeda = v => 'R$ ' + Number(v||0).toLocaleString('pt-BR',{minimumFractionDigits:2});
const diasSemAtualizar = (dataStr) => {
  if(!dataStr) return 999;
  const d = new Date(dataStr);
  return Math.floor((hoje - d)/(1000*60*60*24));
};

// ── IMPRESSAO ────────────────────────────────────────────────
const printOS = (os, clientes) => {
  const cli = clientes.find(c=>c.id===os.clienteId);
  const win = window.open('','_blank');
  win.document.write(`<html><head><title>OS ${os.id}</title><style>body{font-family:Georgia,serif;padding:40px;color:#111} h1{font-size:22px} table{width:100%;border-collapse:collapse} td,th{border:1px solid #ddd;padding:8px;font-size:13px} .gold{color:#B8972A}</style></head><body>
    <div style="text-align:center;margin-bottom:30px"><h1 class="gold">Atelie Das G - Ordem de Servico</h1><h2>${os.id}</h2></div>
    <table><tr><th>Cliente</th><td>${cli?.nome}</td><th>Telefone</th><td>${cli?.fone}</td></tr>
    <tr><th>Descricao</th><td colspan="3">${os.descricao}</td></tr>
    <tr><th>Status</th><td>${fluxoLabel(os.status)}</td><th>Data Evento</th><td>${os.dataEvento}</td></tr>
    <tr><th>Valor Total</th><td>${moeda(os.valorTotal)}</td><th>Valor Pago</th><td>${moeda(os.valorPago)}</td></tr>
    <tr><th>Observacoes</th><td colspan="3">${os.obs}</td></tr></table>
    <p style="margin-top:30px;font-size:11px;color:#888">Emitido em ${fmt(hoje)}</p>
    <script>window.print()</script></body></html>`);
};

const printOrcamento = (orc, clientes) => {
  const cli = clientes.find(c=>c.id===orc.clienteId);
  const subtotal = orc.itens.reduce((a,i)=>a+Number(i.valor),0);
  const total = subtotal * (1 + orc.overhead/100) * (1 + orc.margem/100);
  const win = window.open('','_blank');
  win.document.write(`<html><head><title>ORC ${orc.id}</title><style>body{font-family:Georgia,serif;padding:40px;color:#111} h1{font-size:20px} table{width:100%;border-collapse:collapse} td,th{border:1px solid #ddd;padding:8px;font-size:13px} .gold{color:#B8972A} .total{font-weight:bold;font-size:15px}</style></head><body>
    <div style="text-align:center;margin-bottom:30px"><h1 class="gold">Atelie Das G - Orcamento</h1><h2>${orc.id} - ${cli?.nome}</h2></div>
    <table><tr><th>Item</th><th>Valor</th></tr>
    ${orc.itens.map(i=>`<tr><td>${i.desc}</td><td style="text-align:right">${moeda(i.valor)}</td></tr>`).join('')}
    <tr><td>Overhead (${orc.overhead}%)</td><td style="text-align:right">${moeda(subtotal*orc.overhead/100)}</td></tr>
    <tr><td>Margem (${orc.margem}%)</td><td style="text-align:right">${moeda(subtotal*(1+orc.overhead/100)*orc.margem/100)}</td></tr>
    <tr class="total"><td>TOTAL</td><td style="text-align:right">${moeda(total)}</td></tr></table>
    <p style="margin-top:30px;font-size:11px;color:#888">Orcamento valido por 15 dias. Emitido em ${fmt(hoje)}</p>
    <script>window.print()</script></body></html>`);
};

