// ── DASHBOARD ────────────────────────────────────────────────
const Dashboard = ({ os, clientes, agenda, pedidos, tarefas, conversas, setTarefas }) => {
  const agendaHoje = agenda.filter(a => a.data === fmt(hoje));
  const vendas = { cakto:0, loja:0, atelie:0 };
  pedidos.forEach(p => { if(p.pagamentos.length) p.pagamentos.forEach(pg => { if(vendas[p.canal]!==undefined) vendas[p.canal] += pg.valor; }); });
  const aReceber = pedidos.reduce((a,p)=>a+(p.valor - p.pagamentos.reduce((s,pg)=>s+pg.valor,0)),0);
  const osParadas = os.filter(o => diasSemAtualizar(o.ultimaAtualizacao) >= 14 && o.status !== 'entregue');
  const tarefasHoje = tarefas.filter(t => !t.feita);

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:20 }}>
      {/* Metricas */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(180px,1fr))', gap:14 }}>
        {[
          { label:'Vendas Cakto', valor: moeda(vendas.cakto), cor: C.purple },
          { label:'Vendas Loja', valor: moeda(vendas.loja), cor: C.blue },
          { label:'Vendas Atelie', valor: moeda(vendas.atelie), cor: C.gold },
          { label:'A Receber', valor: moeda(aReceber), cor: C.green },
          { label:'OS Paradas (+14d)', valor: osParadas.length, cor: osParadas.length>0?C.red:C.green },
        ].map(m => (
          <Card key={m.label} style={{ borderTop:`3px solid ${m.cor}` }}>
            <div style={{ fontSize:11, color: C.textMid, fontWeight:600, textTransform:'uppercase', letterSpacing:.5, marginBottom:6 }}>{m.label}</div>
            <div style={{ fontSize:22, fontWeight:800, color: m.cor }}>{m.valor}</div>
          </Card>
        ))}
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
        {/* Agenda do dia */}
        <Card>
          <h3 style={{ margin:'0 0 14px', fontSize:14, color: C.text, fontWeight:700, borderBottom:`1px solid ${C.border}`, paddingBottom:10 }}>Agenda de Hoje</h3>
          {agendaHoje.length === 0 && <p style={{ color: C.textLight, fontSize:13 }}>Nenhum compromisso hoje.</p>}
          {agendaHoje.map(a => {
            const cli = clientes.find(c=>c.id===a.clienteId);
            return (
              <div key={a.id} style={{ display:'flex', gap:12, alignItems:'flex-start', marginBottom:12, paddingBottom:12, borderBottom:`1px solid ${C.border}` }}>
                <div style={{ minWidth:48, textAlign:'center', background: C.goldPale, borderRadius:8, padding:'4px 6px' }}>
                  <div style={{ fontSize:14, fontWeight:800, color: C.gold }}>{a.hora}</div>
                </div>
                <div>
                  <div style={{ fontSize:13, fontWeight:600, color: C.text }}>{a.desc}</div>
                  <div style={{ fontSize:11, color: C.textMid }}>{cli?.nome} - {a.tipo} ({a.durMin}min)</div>
                </div>
              </div>
            );
          })}
        </Card>

        {/* Tarefas do dia */}
        <Card>
          <h3 style={{ margin:'0 0 14px', fontSize:14, color: C.text, fontWeight:700, borderBottom:`1px solid ${C.border}`, paddingBottom:10 }}>Tarefas Pendentes</h3>
          {tarefasHoje.length === 0 && <p style={{ color: C.green, fontSize:13, fontWeight:600 }}>Tudo em dia!</p>}
          {tarefasHoje.map(t => (
            <div key={t.id} style={{ display:'flex', gap:10, alignItems:'center', marginBottom:10 }}>
              <input type="checkbox" checked={t.feita} onChange={() => setTarefas(prev=>prev.map(x=>x.id===t.id?{...x,feita:!x.feita}:x))} style={{ width:16, height:16, accentColor: C.gold }} />
              <span style={{ fontSize:13, color: C.text, textDecoration: t.feita?'line-through':'' }}>{t.desc}</span>
              <Tag label={t.prioridade} cor={t.prioridade==='alta'?C.red:t.prioridade==='media'?C.orange:C.textMid} corPale={t.prioridade==='alta'?C.redPale:t.prioridade==='media'?C.orangePale:C.bg} small />
            </div>
          ))}
        </Card>

        {/* WhatsApp */}
        <Card>
          <h3 style={{ margin:'0 0 14px', fontSize:14, color: C.text, fontWeight:700, borderBottom:`1px solid ${C.border}`, paddingBottom:10 }}>WhatsApp - Conversas</h3>
          {conversas.map(cv => (
            <div key={cv.id} style={{ display:'flex', gap:12, alignItems:'center', marginBottom:12, paddingBottom:12, borderBottom:`1px solid ${C.border}` }}>
              <div style={{ width:38, height:38, borderRadius:'50%', background: C.goldPale, display:'flex', alignItems:'center', justifyContent:'center', fontSize:15, fontWeight:800, color: C.gold, flexShrink:0 }}>{cv.nome[0]}</div>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                  <span style={{ fontSize:13, fontWeight:700, color: C.text }}>{cv.nome}</span>
                  <span style={{ fontSize:10, color: C.textLight }}>{cv.hora}</span>
                </div>
                <div style={{ fontSize:12, color: C.textMid, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{cv.ultima}</div>
              </div>
              {cv.naoLidas > 0 && <span style={{ background: C.green, color:'#fff', borderRadius:'50%', width:18, height:18, display:'flex', alignItems:'center', justifyContent:'center', fontSize:10, fontWeight:700, flexShrink:0 }}>{cv.naoLidas}</span>}
            </div>
          ))}
        </Card>

        {/* OS Paradas */}
        <Card>
          <h3 style={{ margin:'0 0 14px', fontSize:14, color: C.text, fontWeight:700, borderBottom:`1px solid ${C.border}`, paddingBottom:10 }}>
            Atencao - OS Paradas
          </h3>
          {osParadas.length === 0 && <p style={{ color: C.green, fontSize:13, fontWeight:600 }}>Nenhuma OS parada.</p>}
          {osParadas.map(o => {
            const cli = clientes.find(c=>c.id===o.clienteId);
            const dias = diasSemAtualizar(o.ultimaAtualizacao);
            return (
              <div key={o.id} style={{ marginBottom:12, paddingBottom:12, borderBottom:`1px solid ${C.border}` }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                  <span style={{ fontSize:13, fontWeight:700, color: C.text }}>{o.id} - {cli?.nome}</span>
                  <Tag label={`${dias} dias`} cor={C.red} corPale={C.redPale} small />
                </div>
                <div style={{ fontSize:11, color: C.textMid, marginTop:3 }}>{o.descricao}</div>
                <StatusBadge status={o.status} />
              </div>
            );
          })}
        </Card>
      </div>
    </div>
  );
};


// ── CLIENTES ─────────────────────────────────────────────────
const Clientes = ({ clientes, os, setClientes }) => {
  const [busca, setBusca] = useState('');
  const [selecionado, setSelecionado] = useState(null);
  const [abaDetalhe, setAbaDetalhe] = useState('Dados');
  const [novo, setNovo] = useState(false);
  const [form, setForm] = useState({ nome:'', fone:'', email:'', papel:'', vestido:'', cor:'', eventoData:'', obs:'', medidas:{ busto:'', cintura:'', quadril:'', comp:'', ombro:'' }, endereco:{ rua:'', bairro:'', cidade:'', uf:'SP', cep:'', cpf:'' } });
  const fileRef = useRef();

  const papeis = ['Noiva','Mae de Noiva','Mae de Noivo','Madrinha','Dama de Honra','Convidada','Debutante','Outro'];
  const filtrados = clientes.filter(c => c.nome.toLowerCase().includes(busca.toLowerCase()) || c.papel.toLowerCase().includes(busca.toLowerCase()));

  const clienteOS = (id) => os.filter(o=>o.clienteId===id);

  const salvar = () => {
    if(!form.nome) return;
    if(selecionado && novo===false) {
      setClientes(prev=>prev.map(c=>c.id===selecionado.id?{...selecionado,...form,id:selecionado.id}:c));
    } else {
      const nc = { ...form, id: Date.now(), status:'ativo', fotos:[], medidas: form.medidas, endereco: form.endereco };
      setClientes(prev=>[...prev,nc]);
    }
    setNovo(false); setSelecionado(null);
  };

  const abrirEdicao = (c) => {
    setSelecionado(c);
    setForm({ nome:c.nome, fone:c.fone, email:c.email, papel:c.papel, vestido:c.vestido, cor:c.cor, eventoData:c.eventoData, obs:c.obs, medidas:{...c.medidas}, endereco:{...c.endereco} });
    setAbaDetalhe('Dados');
  };

  const handleFoto = (e) => {
    const f = e.target.files[0];
    if(!f||!selecionado) return;
    const reader = new FileReader();
    reader.onload = ev => {
      setClientes(prev=>prev.map(c=>c.id===selecionado.id?{...c,fotos:[...(c.fotos||[]),{url:ev.target.result,nome:f.name}]}:c));
      setSelecionado(prev=>({...prev,fotos:[...(prev.fotos||[]),{url:ev.target.result,nome:f.name}]}));
    };
    reader.readAsDataURL(f);
  };

  return (
    <div style={{ display:'flex', gap:20, height:'100%' }}>
      {/* Lista */}
      <div style={{ flex:1, minWidth:0 }}>
        <div style={{ display:'flex', gap:10, marginBottom:16, alignItems:'center' }}>
          <Inp value={busca} onChange={setBusca} placeholder="Buscar cliente..." style={{ flex:1 }} />
          <Btn onClick={()=>{ setNovo(true); setSelecionado(null); setForm({ nome:'',fone:'',email:'',papel:'',vestido:'',cor:'',eventoData:'',obs:'',medidas:{busto:'',cintura:'',quadril:'',comp:'',ombro:''},endereco:{rua:'',bairro:'',cidade:'',uf:'SP',cep:'',cpf:''} }); }}>+ Nova Cliente</Btn>
        </div>

        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
            <thead>
              <tr style={{ background: C.goldPale }}>
                {['Nome','Vestido / Cor','Papel','Data Evento','OS / Status'].map(h=>(
                  <th key={h} style={{ padding:'10px 12px', textAlign:'left', fontSize:11, fontWeight:700, color: C.gold, textTransform:'uppercase', letterSpacing:.4, borderBottom:`2px solid ${C.border}` }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtrados.map((c,i)=>{
                const osCli = clienteOS(c.id);
                const ultimaOS = osCli[osCli.length-1];
                return (
                  <tr key={c.id} onClick={()=>abrirEdicao(c)} style={{ background: i%2===0?'#fff':C.bg, cursor:'pointer', transition:'background .1s' }}
                    onMouseOver={e=>e.currentTarget.style.background=C.goldPale} onMouseOut={e=>e.currentTarget.style.background=i%2===0?'#fff':C.bg}>
                    <td style={{ padding:'10px 12px', fontWeight:700, color: C.text }}>{c.nome}</td>
                    <td style={{ padding:'10px 12px', color: C.textMid }}>{c.vestido}{c.cor?' / '+c.cor:''}</td>
                    <td style={{ padding:'10px 12px' }}><Tag label={c.papel||'-'} cor={C.blue} corPale={C.bluePale} small /></td>
                    <td style={{ padding:'10px 12px', color: C.textMid }}>{c.eventoData ? new Date(c.eventoData+'T00:00:00').toLocaleDateString('pt-BR') : '-'}</td>
                    <td style={{ padding:'10px 12px' }}>{ultimaOS ? <StatusBadge status={ultimaOS.status} /> : <span style={{ color: C.textLight, fontSize:12 }}>Sem OS</span>}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Detalhe / Formulario */}
      {(selecionado || novo) && (
        <div style={{ width:380, background: C.card, border:`1px solid ${C.border}`, borderRadius:10, padding:20, boxShadow: C.shadowMd, overflowY:'auto', maxHeight:'80vh' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:16 }}>
            <h3 style={{ margin:0, fontSize:15, color: C.text }}>{novo?'Nova Cliente':selecionado?.nome}</h3>
            <button onClick={()=>{setSelecionado(null);setNovo(false);}} style={{ border:'none', background:'none', cursor:'pointer', fontSize:18, color: C.textLight }}>x</button>
          </div>

          {!novo && <Tabs tabs={['Dados','Medidas','Fotos','Historico']} active={abaDetalhe} onChange={setAbaDetalhe} />}

          {(novo||abaDetalhe==='Dados') && (
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              <Inp label="Nome" value={form.nome} onChange={v=>setForm(p=>({...p,nome:v}))} />
              <Inp label="Telefone" value={form.fone} onChange={v=>setForm(p=>({...p,fone:v}))} />
              <Inp label="E-mail" value={form.email} onChange={v=>setForm(p=>({...p,email:v}))} />
              <Sel label="Papel" value={form.papel} onChange={v=>setForm(p=>({...p,papel:v}))} opts={papeis} />
              <Inp label="Vestido / Peca" value={form.vestido} onChange={v=>setForm(p=>({...p,vestido:v}))} />
              <Inp label="Cor" value={form.cor} onChange={v=>setForm(p=>({...p,cor:v}))} />
              <Inp label="Data do Evento" type="date" value={form.eventoData} onChange={v=>setForm(p=>({...p,eventoData:v}))} />
              <Inp label="CPF (NF-e)" value={form.endereco.cpf} onChange={v=>setForm(p=>({...p,endereco:{...p.endereco,cpf:v}}))} />
              <Inp label="Rua e Nr" value={form.endereco.rua} onChange={v=>setForm(p=>({...p,endereco:{...p.endereco,rua:v}}))} />
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                <Inp label="Cidade" value={form.endereco.cidade} onChange={v=>setForm(p=>({...p,endereco:{...p.endereco,cidade:v}}))} />
                <Inp label="UF" value={form.endereco.uf} onChange={v=>setForm(p=>({...p,endereco:{...p.endereco,uf:v}}))} />
              </div>
              <Txt label="Observacoes" value={form.obs} onChange={v=>setForm(p=>({...p,obs:v}))} rows={2} />
              <Btn onClick={salvar}>Salvar</Btn>
            </div>
          )}

          {!novo && abaDetalhe==='Medidas' && (
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              {['busto','cintura','quadril','comp','ombro'].map(m=>(
                <Inp key={m} label={m.charAt(0).toUpperCase()+m.slice(1)+' (cm)'} type="number" value={form.medidas[m]} onChange={v=>setForm(p=>({...p,medidas:{...p.medidas,[m]:v}}))} />
              ))}
              <Btn onClick={salvar}>Salvar Medidas</Btn>
            </div>
          )}

          {!novo && abaDetalhe==='Fotos' && (
            <div>
              <input type="file" accept="image/*" ref={fileRef} onChange={handleFoto} style={{ display:'none' }} />
              <Btn onClick={()=>fileRef.current.click()} style={{ marginBottom:16 }}>Adicionar Foto</Btn>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                {(selecionado?.fotos||[]).map((f,i)=>(
                  <img key={i} src={f.url} alt={f.nome} style={{ width:'100%', height:120, objectFit:'cover', borderRadius:8, border:`1px solid ${C.border}` }} />
                ))}
              </div>
              {!(selecionado?.fotos?.length) && <p style={{ color: C.textLight, fontSize:13 }}>Nenhuma foto adicionada.</p>}
            </div>
          )}

          {!novo && abaDetalhe==='Historico' && (
            <div>
              {clienteOS(selecionado?.id).map(o=>(
                <div key={o.id} style={{ marginBottom:12, paddingBottom:12, borderBottom:`1px solid ${C.border}` }}>
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                    <span style={{ fontWeight:700, fontSize:13 }}>{o.id}</span>
                    <StatusBadge status={o.status} />
                  </div>
                  <div style={{ fontSize:12, color: C.textMid, marginTop:4 }}>{o.descricao}</div>
                  <div style={{ fontSize:11, color: C.textLight }}>Abertura: {o.dataAbertura}</div>
                </div>
              ))}
              {!clienteOS(selecionado?.id).length && <p style={{ color: C.textLight, fontSize:13 }}>Nenhuma OS para esta cliente.</p>}
            </div>
          )}
        </div>
      )}
    </div>
  );
};


// ── FLUXO / KANBAN ───────────────────────────────────────────
const FluxoAtendimento = ({ os, clientes, setOs }) => {
  const [filtro, setFiltro] = useState('todos');
  const [detalhe, setDetalhe] = useState(null);

  const osVisiveis = os.filter(o => filtro==='todos' || o.status===filtro);

  const moverStatus = (osId, direcao) => {
    setOs(prev=>prev.map(o=>{
      if(o.id!==osId) return o;
      const idx = FLUXO.findIndex(f=>f.key===o.status);
      const novoIdx = idx+direcao;
      if(novoIdx<0||novoIdx>=FLUXO.length) return o;
      return {...o, status:FLUXO[novoIdx].key, ultimaAtualizacao:new Date().toISOString().split('T')[0]};
    }));
  };

  const osParadas = os.filter(o=>diasSemAtualizar(o.ultimaAtualizacao)>=14 && o.status!=='entregue');

  return (
    <div>
      {osParadas.length>0 && (
        <div style={{ background: C.redPale, border:`1px solid ${C.red}`, borderRadius:8, padding:'12px 16px', marginBottom:16, display:'flex', alignItems:'center', gap:12 }}>
          <span style={{ color: C.red, fontWeight:700, fontSize:13 }}>Atencao: {osParadas.length} OS sem atualizacao ha mais de 14 dias</span>
          <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
            {osParadas.map(o=><Tag key={o.id} label={o.id} cor={C.red} corPale={C.redPale} small />)}
          </div>
        </div>
      )}

      {/* Filtro por status */}
      <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginBottom:16 }}>
        <Btn onClick={()=>setFiltro('todos')} variant={filtro==='todos'?'primary':'ghost'} small>Todos ({os.length})</Btn>
        {FLUXO.map(f=>{
          const count = os.filter(o=>o.status===f.key).length;
          if(!count) return null;
          return <Btn key={f.key} onClick={()=>setFiltro(f.key)} variant={filtro===f.key?'primary':'ghost'} small>{f.label} ({count})</Btn>;
        })}
      </div>

      {/* Cards das OS */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))', gap:14 }}>
        {osVisiveis.map(o=>{
          const cli = clientes.find(c=>c.id===o.clienteId);
          const dias = diasSemAtualizar(o.ultimaAtualizacao);
          const parada = dias>=14;
          const fObj = fluxoObj(o.status);
          const idxAtual = FLUXO.findIndex(f=>f.key===o.status);
          const saldo = o.valorTotal - o.valorPago;
          return (
            <Card key={o.id} style={{ borderLeft:`4px solid ${fObj.cor}`, borderColor: parada?C.red:fObj.cor }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
                <div>
                  <div style={{ fontSize:12, color: C.textLight, fontWeight:600 }}>{o.id}</div>
                  <div style={{ fontSize:15, fontWeight:800, color: C.text }}>{cli?.nome}</div>
                  <div style={{ fontSize:12, color: C.textMid }}>{o.descricao}</div>
                </div>
                {parada && <Tag label={`${dias}d parada`} cor={C.red} corPale={C.redPale} small />}
              </div>

              <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap' }}>
                <StatusBadge status={o.status} />
                <Tag label={`Evento: ${o.dataEvento ? new Date(o.dataEvento+'T00:00:00').toLocaleDateString('pt-BR') : '-'}`} cor={C.blue} corPale={C.bluePale} small />
              </div>

              <div style={{ marginBottom:12 }}>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, marginBottom:4 }}>
                  <span style={{ color: C.textMid }}>Pago: {moeda(o.valorPago)}</span>
                  <span style={{ color: saldo>0?C.red:C.green, fontWeight:700 }}>Saldo: {moeda(saldo)}</span>
                </div>
                <div style={{ height:4, background: C.border, borderRadius:2 }}>
                  <div style={{ height:4, background: C.gold, borderRadius:2, width:`${Math.min(100,(o.valorPago/o.valorTotal)*100)}%` }} />
                </div>
              </div>

              {/* Progresso do fluxo */}
              <div style={{ display:'flex', gap:3, flexWrap:'wrap', marginBottom:12 }}>
                {FLUXO.map((f,i)=>(
                  <div key={f.key} title={f.label} style={{ width:10, height:10, borderRadius:'50%', background: i<=idxAtual?f.cor:C.border, transition:'background .2s' }} />
                ))}
              </div>

              <div style={{ display:'flex', gap:8, justifyContent:'space-between' }}>
                <div style={{ display:'flex', gap:6 }}>
                  <Btn onClick={()=>moverStatus(o.id,-1)} variant="ghost" small disabled={idxAtual===0}>Voltar</Btn>
                  <Btn onClick={()=>moverStatus(o.id,1)} small disabled={idxAtual===FLUXO.length-1}>Avancar</Btn>
                </div>
                <Btn onClick={()=>setDetalhe(o)} variant="outline" small>Ver OS</Btn>
              </div>
            </Card>
          );
        })}
      </div>

      {/* Modal detalhe OS */}
      {detalhe && <OSDetalhe os={detalhe} clientes={clientes} setOs={setOs} onClose={()=>setDetalhe(null)} />}
    </div>
  );
};

// ── OS DETALHE / MODAL ────────────────────────────────────────
const OSDetalhe = ({ os, clientes, setOs, onClose }) => {
  const [aba, setAba] = useState('Dados');
  const [form, setForm] = useState({ descricao:os.descricao, obs:os.obs, valorTotal:os.valorTotal, dataEvento:os.dataEvento, status:os.status });
  const fileRef = useRef();

  const cli = clientes.find(c=>c.id===os.clienteId);
  const saldo = os.valorTotal - os.valorPago;

  const salvar = () => {
    setOs(prev=>prev.map(o=>o.id===os.id?{...o,...form,ultimaAtualizacao:new Date().toISOString().split('T')[0]}:o));
    onClose();
  };

  const handleFoto = (e) => {
    const f = e.target.files[0];
    if(!f) return;
    const reader = new FileReader();
    reader.onload = ev => {
      setOs(prev=>prev.map(o=>o.id===os.id?{...o,fotos:[...(o.fotos||[]),{url:ev.target.result,nome:f.name}]}:o));
    };
    reader.readAsDataURL(f);
  };

  return (
    <Modal title={`${os.id} - ${cli?.nome}`} onClose={onClose} wide>
      <Tabs tabs={['Dados','Provas','Fotos','Impressao']} active={aba} onChange={setAba} />

      {aba==='Dados' && (
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <Inp label="Descricao" value={form.descricao} onChange={v=>setForm(p=>({...p,descricao:v}))} />
          <Inp label="Data Evento" type="date" value={form.dataEvento} onChange={v=>setForm(p=>({...p,dataEvento:v}))} />
          <Inp label="Valor Total (R$)" type="number" value={form.valorTotal} onChange={v=>setForm(p=>({...p,valorTotal:Number(v)}))} />
          <Sel label="Status" value={form.status} onChange={v=>setForm(p=>({...p,status:v}))} opts={FLUXO.map(f=>({value:f.key,label:f.label}))} />
          <div style={{ gridColumn:'1/-1' }}><Txt label="Observacoes" value={form.obs} onChange={v=>setForm(p=>({...p,obs:v}))} rows={3} /></div>
          <div style={{ gridColumn:'1/-1', display:'flex', gap:10 }}>
            <div style={{ background: C.greenPale, borderRadius:8, padding:'10px 16px', flex:1 }}>
              <div style={{ fontSize:11, color: C.green, fontWeight:700 }}>PAGO</div>
              <div style={{ fontSize:18, fontWeight:800, color: C.green }}>{moeda(os.valorPago)}</div>
            </div>
            <div style={{ background: saldo>0?C.redPale:C.greenPale, borderRadius:8, padding:'10px 16px', flex:1 }}>
              <div style={{ fontSize:11, color: saldo>0?C.red:C.green, fontWeight:700 }}>SALDO</div>
              <div style={{ fontSize:18, fontWeight:800, color: saldo>0?C.red:C.green }}>{moeda(saldo)}</div>
            </div>
          </div>
          <div style={{ gridColumn:'1/-1' }}><Btn onClick={salvar}>Salvar OS</Btn></div>
        </div>
      )}

      {aba==='Provas' && (
        <div>
          <p style={{ color: C.textMid, fontSize:13 }}>Registro de provas e ajustes da OS.</p>
          {(os.provas||[]).map((p,i)=>(
            <div key={i} style={{ background: C.bg, borderRadius:8, padding:12, marginBottom:10 }}>
              <div style={{ fontWeight:700, fontSize:13 }}>{p.tipo} - {p.data}</div>
              <div style={{ color: C.textMid, fontSize:12 }}>{p.obs}</div>
            </div>
          ))}
          {!os.provas?.length && <p style={{ color: C.textLight, fontSize:13 }}>Nenhuma prova registrada.</p>}
        </div>
      )}

      {aba==='Fotos' && (
        <div>
          <input type="file" accept="image/*" ref={fileRef} onChange={handleFoto} style={{ display:'none' }} />
          <Btn onClick={()=>fileRef.current.click()} style={{ marginBottom:16 }}>Adicionar Foto</Btn>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:10 }}>
            {(os.fotos||[]).map((f,i)=>(
              <img key={i} src={f.url} alt={f.nome} style={{ width:'100%', height:120, objectFit:'cover', borderRadius:8, border:`1px solid ${C.border}` }} />
            ))}
          </div>
          {!os.fotos?.length && <p style={{ color: C.textLight, fontSize:13 }}>Nenhuma foto adicionada.</p>}
        </div>
      )}

      {aba==='Impressao' && (
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          <p style={{ color: C.textMid, fontSize:13 }}>Selecione o documento a imprimir:</p>
          <Btn onClick={()=>printOS(os,clientes)}>Imprimir Ordem de Servico</Btn>
        </div>
      )}
    </Modal>
  );
};


// ── BRIEFING / CRIACAO / DOSSIE ────────────────────────────
const BriefingDossie = ({ clientes, briefings, setBriefings, os }) => {
  const [clienteId, setClienteId] = useState('');
  const [aba, setAba] = useState('Briefing');
  const [form, setForm] = useState({ ocasiao:'', estilo:'', tecidos:'', cores:'', refs:'', corpo:'', obs:'' });
  const [dossie, setDossie] = useState('');
  const [status, setStatus] = useState('rascunho');

  const bAtual = briefings.find(b=>b.clienteId===Number(clienteId));
  const cli = clientes.find(c=>c.id===Number(clienteId));

  const carregarBriefing = (cId) => {
    setClienteId(cId);
    const b = briefings.find(b=>b.clienteId===Number(cId));
    if(b) { setForm({...b.respostas}); setDossie(b.dossie||''); setStatus(b.status||'rascunho'); }
    else { setForm({ ocasiao:'',estilo:'',tecidos:'',cores:'',refs:'',corpo:'',obs:'' }); setDossie(''); setStatus('rascunho'); }
  };

  const salvarBriefing = () => {
    if(!clienteId) return;
    setBriefings(prev=>{
      const existe = prev.find(b=>b.clienteId===Number(clienteId));
      const obj = { id: existe?.id||Date.now(), clienteId:Number(clienteId), respostas:{...form}, dossie, status };
      if(existe) return prev.map(b=>b.clienteId===Number(clienteId)?obj:b);
      return [...prev,obj];
    });
    alert('Briefing salvo!');
  };

  const statusDossie = [
    { key:'rascunho', label:'Rascunho', cor: C.textMid },
    { key:'pendente', label:'Pendente Aprovacao', cor: C.orange },
    { key:'aprovado', label:'Aprovado por Ju', cor: C.green },
    { key:'enviado', label:'Enviado a Cliente', cor: C.blue },
  ];

  return (
    <div>
      <div style={{ display:'flex', gap:12, alignItems:'center', marginBottom:20 }}>
        <Sel label="Cliente" value={clienteId} onChange={carregarBriefing} opts={[{value:'',label:'Selecione...'}, ...clientes.map(c=>({value:c.id,label:c.nome}))]} style={{ minWidth:220 }} />
        {bAtual && <Tag label={statusDossie.find(s=>s.key===status)?.label||status} cor={statusDossie.find(s=>s.key===status)?.cor} corPale={C.bg} />}
      </div>

      {!clienteId && <div style={{ color: C.textLight, fontSize:14, textAlign:'center', padding:40 }}>Selecione uma cliente para comecar</div>}

      {clienteId && (
        <div>
          <Tabs tabs={['Briefing','Criacao','Dossie']} active={aba} onChange={setAba} />

          {aba==='Briefing' && (
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              <Inp label="Ocasiao" value={form.ocasiao} onChange={v=>setForm(p=>({...p,ocasiao:v}))} placeholder="Ex: Casamento ao ar livre" />
              <Inp label="Estilo desejado" value={form.estilo} onChange={v=>setForm(p=>({...p,estilo:v}))} placeholder="Ex: Romantico, moderno..." />
              <Inp label="Tecidos preferidos" value={form.tecidos} onChange={v=>setForm(p=>({...p,tecidos:v}))} placeholder="Ex: Renda, tule, crepe..." />
              <Inp label="Cores" value={form.cores} onChange={v=>setForm(p=>({...p,cores:v}))} placeholder="Ex: Branco perola, sage..." />
              <Inp label="Referencias (links/desc)" value={form.refs} onChange={v=>setForm(p=>({...p,refs:v}))} placeholder="Pinterest, referencias..." />
              <Inp label="Corpo / Ajustes necessarios" value={form.corpo} onChange={v=>setForm(p=>({...p,corpo:v}))} placeholder="Ex: Quadril maior, busto G..." />
              <div style={{ gridColumn:'1/-1' }}>
                <Txt label="Observacoes gerais" value={form.obs} onChange={v=>setForm(p=>({...p,obs:v}))} rows={3} />
              </div>
              <div style={{ gridColumn:'1/-1' }}><Btn onClick={salvarBriefing}>Salvar Briefing</Btn></div>
            </div>
          )}

          {aba==='Criacao' && (
            <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
              <Card style={{ background: C.goldPale }}>
                <h4 style={{ margin:'0 0 12px', color: C.gold, fontSize:13, fontWeight:700 }}>Resumo do Briefing</h4>
                {Object.entries(form).map(([k,v])=>v?(
                  <div key={k} style={{ marginBottom:6 }}>
                    <span style={{ fontSize:11, fontWeight:700, color: C.textMid, textTransform:'uppercase' }}>{k}: </span>
                    <span style={{ fontSize:13, color: C.text }}>{v}</span>
                  </div>
                ):null)}
              </Card>
              <Txt label="Notas de Criacao e Referencias Visuais" value={dossie} onChange={setDossie} rows={8} placeholder="Descreva a proposta criativa, silhueta, detalhes, referencias de construcao..." />
              <Btn onClick={salvarBriefing}>Salvar Criacao</Btn>
            </div>
          )}

          {aba==='Dossie' && (
            <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
              <div style={{ display:'flex', gap:10, alignItems:'center', flexWrap:'wrap' }}>
                <span style={{ fontSize:13, fontWeight:600, color: C.textMid }}>Status do Dossie:</span>
                {statusDossie.map(s=>(
                  <Btn key={s.key} onClick={()=>setStatus(s.key)} variant={status===s.key?'primary':'ghost'} small style={{ background: status===s.key?s.cor:'transparent', borderColor: s.cor, color: status===s.key?'#fff':s.cor }}>{s.label}</Btn>
                ))}
              </div>

              <Card style={{ borderLeft:`4px solid ${C.gold}`, background: C.goldPale }}>
                <h4 style={{ margin:'0 0 8px', color: C.gold }}>Proposta Criativa</h4>
                {dossie ? <p style={{ margin:0, fontSize:14, color: C.text, lineHeight:1.7 }}>{dossie}</p> : <p style={{ color: C.textLight, fontSize:13 }}>Elabore a proposta na aba Criacao antes de revisar o dossie.</p>}
              </Card>

              <div style={{ display:'flex', gap:10 }}>
                <Btn onClick={salvarBriefing}>Salvar Status</Btn>
                {bAtual && <Btn onClick={()=>printDossie(bAtual, clientes)} variant="outline">Imprimir Dossie</Btn>}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};


// ── ORCAMENTOS ────────────────────────────────────────────────
const Orcamentos = ({ clientes, orcamentos, setOrcamentos, os, setOs, printOrcamento: printOrc }) => {
  const [sel, setSel] = useState(null);
  const [form, setForm] = useState({ clienteId:'', osId:'', itens:[{desc:'',valor:''}], overhead:15, margem:20, status:'rascunho', data: new Date().toISOString().split('T')[0] });
  const [novo, setNovo] = useState(false);

  const subtotal = (itens) => itens.reduce((a,i)=>a+Number(i.valor||0),0);
  const calcTotal = (itens,oh,mg) => subtotal(itens)*(1+Number(oh)/100)*(1+Number(mg)/100);

  const addItem = () => setForm(p=>({...p, itens:[...p.itens,{desc:'',valor:''}]}));
  const rmItem  = (i) => setForm(p=>({...p, itens:p.itens.filter((_,idx)=>idx!==i)}));
  const updItem = (i,field,val) => setForm(p=>({...p, itens:p.itens.map((it,idx)=>idx===i?{...it,[field]:val}:it)}));

  const salvar = () => {
    if(!form.clienteId) { alert('Selecione uma cliente'); return; }
    if(form.itens.some(i=>!i.desc||!i.valor)) { alert('Preencha todos os itens'); return; }
    const id = sel?.id || 'ORC-'+String(orcamentos.length+1).padStart('3','0');
    const obj = { ...form, id, clienteId:Number(form.clienteId), valorTotal: calcTotal(form.itens,form.overhead,form.margem) };
    setOrcamentos(prev => sel ? prev.map(o=>o.id===sel.id?obj:o) : [...prev,obj]);
    setSel(null); setNovo(false);
  };

  const abrirNovo = () => {
    setNovo(true); setSel(null);
    setForm({ clienteId:'', osId:'', itens:[{desc:'',valor:''}], overhead:15, margem:20, status:'rascunho', data: new Date().toISOString().split('T')[0] });
  };

  const abrirEdicao = (o) => {
    setSel(o); setNovo(false);
    setForm({ clienteId:String(o.clienteId), osId:o.osId||'', itens:o.itens.map(i=>({...i,valor:String(i.valor)})), overhead:o.overhead, margem:o.margem, status:o.status, data:o.data });
  };

  const statusOrc = ['rascunho','enviado','aprovado','recusado'];
  const corStatus = { rascunho:C.textMid, enviado:C.blue, aprovado:C.green, recusado:C.red };

  return (
    <div style={{ display:'flex', gap:20 }}>
      {/* Lista */}
      <div style={{ flex:1, minWidth:0 }}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:16 }}>
          <h3 style={{ margin:0, fontSize:15 }}>Orcamentos</h3>
          <Btn onClick={abrirNovo}>+ Novo Orcamento</Btn>
        </div>
        {orcamentos.map(o=>{
          const cli = clientes.find(c=>c.id===o.clienteId);
          const tot = calcTotal(o.itens,o.overhead,o.margem);
          return (
            <Card key={o.id} onClick={()=>abrirEdicao(o)} style={{ marginBottom:10, display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div>
                <div style={{ fontWeight:700, fontSize:14 }}>{o.id} - {cli?.nome}</div>
                <div style={{ fontSize:12, color: C.textMid }}>{o.data} | {o.itens.length} item(s)</div>
              </div>
              <div style={{ textAlign:'right' }}>
                <div style={{ fontSize:16, fontWeight:800, color: C.gold }}>{moeda(tot)}</div>
                <Tag label={o.status} cor={corStatus[o.status]} corPale={C.bg} small />
              </div>
            </Card>
          );
        })}
        {!orcamentos.length && <p style={{ color: C.textLight }}>Nenhum orcamento cadastrado.</p>}
      </div>

      {/* Formulario */}
      {(novo||sel) && (
        <div style={{ width:420, background: C.card, border:`1px solid ${C.border}`, borderRadius:10, padding:20, overflowY:'auto', maxHeight:'80vh', boxShadow: C.shadowMd }}>
          <div style={{ display:'flex', justifyContent:'space-between', marginBottom:14 }}>
            <h3 style={{ margin:0, fontSize:15 }}>{sel?'Editar':'Novo'} Orcamento</h3>
            <button onClick={()=>{setSel(null);setNovo(false)}} style={{ border:'none', background:'none', cursor:'pointer', fontSize:18, color: C.textLight }}>x</button>
          </div>

          <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
            <Sel label="Cliente" value={form.clienteId} onChange={v=>setForm(p=>({...p,clienteId:v}))} opts={[{value:'',label:'Selecione...'},...clientes.map(c=>({value:String(c.id),label:c.nome}))]} />
            <Inp label="Data" type="date" value={form.data} onChange={v=>setForm(p=>({...p,data:v}))} />
            <Sel label="Status" value={form.status} onChange={v=>setForm(p=>({...p,status:v}))} opts={statusOrc} />

            <div style={{ borderTop:`1px solid ${C.border}`, paddingTop:12 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:10 }}>
                <label style={{ fontSize:11, fontWeight:700, color: C.textMid, textTransform:'uppercase' }}>Itens</label>
                <Btn onClick={addItem} variant="ghost" small>+ Item</Btn>
              </div>
              {form.itens.map((it,i)=>(
                <div key={i} style={{ display:'flex', gap:8, marginBottom:8, alignItems:'flex-end' }}>
                  <div style={{ flex:2 }}>
                    <input value={it.desc} onChange={e=>updItem(i,'desc',e.target.value)} placeholder="Descricao do item" style={{ width:'100%', padding:'7px 8px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
                  </div>
                  <div style={{ flex:1 }}>
                    <input type="number" value={it.valor} onChange={e=>updItem(i,'valor',e.target.value)} placeholder="R$" style={{ width:'100%', padding:'7px 8px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
                  </div>
                  <button onClick={()=>rmItem(i)} style={{ border:'none', background:'none', cursor:'pointer', color: C.red, fontSize:16, padding:'4px', flexShrink:0 }}>x</button>
                </div>
              ))}
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
              <Inp label="Overhead (%)" type="number" value={form.overhead} onChange={v=>setForm(p=>({...p,overhead:Number(v)}))} />
              <Inp label="Margem (%)" type="number" value={form.margem} onChange={v=>setForm(p=>({...p,margem:Number(v)}))} />
            </div>

            {/* Resumo */}
            <div style={{ background: C.goldPale, borderRadius:8, padding:12 }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color: C.textMid, marginBottom:4 }}>
                <span>Subtotal</span><span>{moeda(subtotal(form.itens))}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color: C.textMid, marginBottom:4 }}>
                <span>Overhead ({form.overhead}%)</span><span>{moeda(subtotal(form.itens)*form.overhead/100)}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color: C.textMid, marginBottom:8 }}>
                <span>Margem ({form.margem}%)</span><span>{moeda(subtotal(form.itens)*(1+form.overhead/100)*form.margem/100)}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontWeight:800, fontSize:16, color: C.gold }}>
                <span>TOTAL</span><span>{moeda(calcTotal(form.itens,form.overhead,form.margem))}</span>
              </div>
            </div>

            <div style={{ display:'flex', gap:10 }}>
              <Btn onClick={salvar} style={{ flex:1 }}>Salvar Orcamento</Btn>
              {sel && <Btn onClick={()=>printOrcamento(sel,clientes)} variant="outline">Imprimir</Btn>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};


// ── FINANCEIRO ────────────────────────────────────────────────
const Financeiro = ({ pedidos, setPedidos, contasFixas, setContasFixas, contasPagar, setContasPagar, clientes }) => {
  const [aba, setAba] = useState('A Receber');
  const [modalPgto, setModalPgto] = useState(null);
  const [pgtoForm, setPgtoForm] = useState({ valor:'', forma:'pix', obs:'' });
  const [novaFixa, setNovaFixa] = useState(false);
  const [fixaForm, setFixaForm] = useState({ desc:'', valor:'', vencimento:'' });
  const [novaPagar, setNovaPagar] = useState(false);
  const [pagarForm, setPagarForm] = useState({ desc:'', valor:'', vencimento:'', fornecedor:'' });

  const formasPgto = ['pix','cartao_debito','cartao_credito','dinheiro','transferencia','link','cakto','cheque'];
  const formaLabel = { pix:'PIX', cartao_debito:'Cartao Debito', cartao_credito:'Cartao Credito', dinheiro:'Dinheiro', transferencia:'Transferencia', link:'Link Pagamento', cakto:'Cakto', cheque:'Cheque' };

  const registrarPagamento = () => {
    if(!pgtoForm.valor||Number(pgtoForm.valor)<=0) { alert('Informe o valor'); return; }
    setPedidos(prev=>prev.map(p=>{
      if(p.id!==modalPgto.id) return p;
      const novoPgto = { data: fmt(hoje), valor:Number(pgtoForm.valor), forma:pgtoForm.forma, obs:pgtoForm.obs };
      const totalPago = [...p.pagamentos,novoPgto].reduce((a,pg)=>a+pg.valor,0);
      const novoStatus = totalPago >= p.valor ? 'pago' : 'parcial';
      return { ...p, pagamentos:[...p.pagamentos,novoPgto], status:novoStatus };
    }));
    setModalPgto(null); setPgtoForm({ valor:'', forma:'pix', obs:'' });
  };

  const totalAReceber = pedidos.reduce((a,p)=>a+(p.valor-p.pagamentos.reduce((s,pg)=>s+pg.valor,0)),0);
  const totalRecebido = pedidos.reduce((a,p)=>a+p.pagamentos.reduce((s,pg)=>s+pg.valor,0),0);
  const totalFixas = contasFixas.filter(c=>c.ativo).reduce((a,c)=>a+c.valor,0);
  const totalPagar = contasPagar.filter(c=>!c.pago).reduce((a,c)=>a+c.valor,0);

  return (
    <div>
      {/* Resumo */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))', gap:12, marginBottom:20 }}>
        {[
          { label:'Total Recebido', valor: moeda(totalRecebido), cor: C.green },
          { label:'A Receber', valor: moeda(totalAReceber), cor: C.orange },
          { label:'Fixas/mes', valor: moeda(totalFixas), cor: C.blue },
          { label:'A Pagar', valor: moeda(totalPagar), cor: C.red },
          { label:'Resultado', valor: moeda(totalRecebido - totalFixas - totalPagar), cor: (totalRecebido-totalFixas-totalPagar)>=0?C.green:C.red },
        ].map(m=>(
          <Card key={m.label} style={{ borderTop:`3px solid ${m.cor}`, textAlign:'center' }}>
            <div style={{ fontSize:11, color: C.textMid, fontWeight:600, textTransform:'uppercase', letterSpacing:.4, marginBottom:4 }}>{m.label}</div>
            <div style={{ fontSize:18, fontWeight:800, color: m.cor }}>{m.valor}</div>
          </Card>
        ))}
      </div>

      <Tabs tabs={['A Receber','Contas a Pagar','Contas Fixas']} active={aba} onChange={setAba} />

      {/* A RECEBER */}
      {aba==='A Receber' && (
        <div>
          {pedidos.map(p=>{
            const cli = clientes.find(c=>c.id===p.clienteId);
            const pago = p.pagamentos.reduce((a,pg)=>a+pg.valor,0);
            const saldo = p.valor-pago;
            const corStatus = { pago:C.green, parcial:C.orange, pendente:C.red }[p.status]||C.textMid;
            return (
              <Card key={p.id} style={{ marginBottom:10 }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', flexWrap:'wrap', gap:10 }}>
                  <div>
                    <div style={{ fontWeight:700, fontSize:14 }}>{p.id} - {cli?.nome}</div>
                    <div style={{ fontSize:12, color: C.textMid }}>{p.desc} | Canal: {p.canal}</div>
                    {p.pagamentos.map((pg,i)=>(
                      <div key={i} style={{ fontSize:11, color: C.textMid, marginTop:3 }}>{pg.data} - {moeda(pg.valor)} via {formaLabel[pg.forma]||pg.forma} {pg.obs&&`(${pg.obs})`}</div>
                    ))}
                  </div>
                  <div style={{ textAlign:'right' }}>
                    <div style={{ fontSize:13, color: C.textMid }}>Total: {moeda(p.valor)}</div>
                    <div style={{ fontSize:13, color: C.green }}>Pago: {moeda(pago)}</div>
                    <div style={{ fontSize:14, fontWeight:800, color: corStatus }}>Saldo: {moeda(saldo)}</div>
                    <Tag label={p.status} cor={corStatus} corPale={C.bg} small />
                  </div>
                </div>
                {saldo>0 && (
                  <div style={{ marginTop:12, borderTop:`1px solid ${C.border}`, paddingTop:10 }}>
                    <Btn onClick={()=>{setModalPgto(p); setPgtoForm({ valor:String(saldo), forma:'pix',  obs:'' })}} small>Registrar Pagamento</Btn>
                  </div>
                )}
              </Card>
            );
          })}
        </div>
      )}

      {/* CONTAS A PAGAR */}
      {aba==='Contas a Pagar' && (
        <div>
          <div style={{ display:'flex', justifyContent:'flex-end', marginBottom:12 }}>
            <Btn onClick={()=>setNovaPagar(true)}>+ Nova Conta</Btn>
          </div>
          {contasPagar.map(c=>(
            <Card key={c.id} style={{ marginBottom:10, borderLeft:`4px solid ${c.pago?C.green:C.red}` }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div>
                  <div style={{ fontWeight:700, fontSize:14 }}>{c.desc}</div>
                  <div style={{ fontSize:12, color: C.textMid }}>{c.fornecedor} | Vence: {c.vencimento}</div>
                </div>
                <div style={{ textAlign:'right', display:'flex', gap:10, alignItems:'center' }}>
                  <div style={{ fontSize:16, fontWeight:800, color: c.pago?C.green:C.red }}>{moeda(c.valor)}</div>
                  {!c.pago && <Btn onClick={()=>setContasPagar(prev=>prev.map(x=>x.id===c.id?{...x,pago:true}:x))} variant="success" small>Pagar</Btn>}
                  {c.pago && <Tag label="Pago" cor={C.green} corPale={C.greenPale} small />}
                </div>
              </div>
            </Card>
          ))}

          {novaPagar && (
            <Modal title="Nova Conta a Pagar" onClose={()=>setNovaPagar(false)}>
              <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
                <Inp label="Descricao" value={pagarForm.desc} onChange={v=>setPagarForm(p=>({...p,desc:v}))} />
                <Inp label="Fornecedor" value={pagarForm.fornecedor} onChange={v=>setPagarForm(p=>({...p,fornecedor:v}))} />
                <Inp label="Valor (R$)" type="number" value={pagarForm.valor} onChange={v=>setPagarForm(p=>({...p,valor:v}))} />
                <Inp label="Vencimento" type="date" value={pagarForm.vencimento} onChange={v=>setPagarForm(p=>({...p,vencimento:v}))} />
                <Btn onClick={()=>{ if(!pagarForm.desc||!pagarForm.valor) return; setContasPagar(prev=>[...prev,{...pagarForm,id:Date.now(),pago:false,valor:Number(pagarForm.valor)}]); setNovaPagar(false); }}>Salvar</Btn>
              </div>
            </Modal>
          )}
        </div>
      )}

      {/* CONTAS FIXAS */}
      {aba==='Contas Fixas' && (
        <div>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
            <span style={{ fontSize:13, color: C.textMid }}>Total mensal: <strong style={{ color: C.blue }}>{moeda(totalFixas)}</strong></span>
            <Btn onClick={()=>{setNovaFixa(true); setFixaForm({desc:'',valor:'',vencimento:''});}}>+ Nova Conta Fixa</Btn>
          </div>
          {contasFixas.map(c=>(
            <Card key={c.id} style={{ marginBottom:10, display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div>
                <div style={{ fontWeight:700, fontSize:14 }}>{c.desc}</div>
                <div style={{ fontSize:12, color: C.textMid }}>Vence dia {c.vencimento} de cada mes</div>
              </div>
              <div style={{ display:'flex', gap:10, alignItems:'center' }}>
                <span style={{ fontSize:16, fontWeight:800, color: C.blue }}>{moeda(c.valor)}</span>
                <button onClick={()=>setContasFixas(prev=>prev.map(x=>x.id===c.id?{...x,ativo:!x.ativo}:x))} style={{ border:'none', background: c.ativo?C.greenPale:C.redPale, color: c.ativo?C.green:C.red, borderRadius:6, padding:'4px 10px', cursor:'pointer', fontSize:12, fontWeight:700 }}>{c.ativo?'Ativo':'Inativo'}</button>
              </div>
            </Card>
          ))}
          {novaFixa && (
            <Modal title="Nova Conta Fixa" onClose={()=>setNovaFixa(false)}>
              <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
                <Inp label="Descricao" value={fixaForm.desc} onChange={v=>setFixaForm(p=>({...p,desc:v}))} />
                <Inp label="Valor (R$)" type="number" value={fixaForm.valor} onChange={v=>setFixaForm(p=>({...p,valor:v}))} />
                <Inp label="Dia de vencimento" type="number" value={fixaForm.vencimento} onChange={v=>setFixaForm(p=>({...p,vencimento:v}))} placeholder="Ex: 5" />
                <Btn onClick={()=>{ if(!fixaForm.desc||!fixaForm.valor) return; setContasFixas(prev=>[...prev,{...fixaForm,id:Date.now(),valor:Number(fixaForm.valor),vencimento:Number(fixaForm.vencimento),ativo:true}]); setNovaFixa(false); }}>Salvar</Btn>
              </div>
            </Modal>
          )}
        </div>
      )}

      {/* Modal pagamento */}
      {modalPgto && (
        <Modal title={`Registrar Pagamento - ${modalPgto.id}`} onClose={()=>setModalPgto(null)}>
          <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
            <div style={{ background: C.goldPale, borderRadius:8, padding:12, marginBottom:4 }}>
              <div style={{ fontSize:13 }}>Saldo em aberto: <strong style={{ color: C.gold }}>{moeda(modalPgto.valor - modalPgto.pagamentos.reduce((a,p)=>a+p.valor,0))}</strong></div>
            </div>
            <Inp label="Valor recebido (R$)" type="number" value={pgtoForm.valor} onChange={v=>setPgtoForm(p=>({...p,valor:v}))} />
            <Sel label="Forma de pagamento" value={pgtoForm.forma} onChange={v=>setPgtoForm(p=>({...p,forma:v}))} opts={formasPgto.map(f=>({value:f,label:formaLabel[f]||f}))} />
            <Inp label="Observacao" value={pgtoForm.obs} onChange={v=>setPgtoForm(p=>({...p,obs:v}))} placeholder="Ex: Entrada, saldo final..." />
            <Btn onClick={registrarPagamento}>Confirmar Pagamento</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
};


// ── AGENDA ────────────────────────────────────────────────────
const Agenda = ({ agenda, setAgenda, clientes, os }) => {
  const [vista, setVista] = useState('diaria');
  const [dataSel, setDataSel] = useState(fmt(hoje));
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState({ data:'', hora:'', tipo:'Prova', clienteId:'', desc:'', durMin:60 });

  const tipos = ['Prova','Briefing','Entrega','Reuniao','Consulta','Outro'];
  const horas = Array.from({length:12},(_,i)=>{ const h=8+i; return `${String(h).padStart(2,'0')}:00`; });

  const eventosData = (d) => agenda.filter(a=>a.data===d).sort((a,b)=>a.hora.localeCompare(b.hora));

  const semanaAtual = () => {
    const d = new Date(dataSel.split('/').reverse().join('-'));
    const days = [];
    const dow = d.getDay();
    for(let i=0;i<7;i++) {
      const day = new Date(d); day.setDate(d.getDate()-dow+i);
      days.push(fmt(day));
    }
    return days;
  };

  const mesAtual = () => {
    const [dd,mm,yyyy] = dataSel.split('/');
    const primeiroDia = new Date(Number(yyyy),Number(mm)-1,1);
    const ultimoDia = new Date(Number(yyyy),Number(mm),0).getDate();
    const dias = [];
    for(let i=1;i<=ultimoDia;i++) dias.push(fmt(new Date(Number(yyyy),Number(mm)-1,i)));
    return dias;
  };

  const salvar = () => {
    if(!form.data||!form.hora||!form.clienteId) { alert('Preencha data, hora e cliente'); return; }
    setAgenda(prev=>[...prev,{...form, clienteId:Number(form.clienteId), id:Date.now()}]);
    setModal(false);
  };

  const corTipo = { Prova: C.purple, Briefing: C.blue, Entrega: C.green, Reuniao: C.gold, Consulta: C.orange, Outro: C.textMid };

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:16, flexWrap:'wrap', gap:10 }}>
        <div style={{ display:'flex', gap:8 }}>
          {['diaria','semanal','mensal'].map(v=>(
            <Btn key={v} onClick={()=>setVista(v)} variant={vista===v?'primary':'ghost'} small>{v.charAt(0).toUpperCase()+v.slice(1)}</Btn>
          ))}
        </div>
        <div style={{ display:'flex', gap:10, alignItems:'center' }}>
          <Inp type="date" value={dataSel.split('/').reverse().join('-')} onChange={v=>setDataSel(fmt(new Date(v+'T00:00:00')))} style={{ padding:'6px 10px' }} />
          <Btn onClick={()=>{setModal(true); setForm({ data:'', hora:'08:00', tipo:'Prova', clienteId:'', desc:'', durMin:60 });}}>+ Agendar</Btn>
        </div>
      </div>

      {/* DIARIA */}
      {vista==='diaria' && (
        <div>
          <h3 style={{ margin:'0 0 16px', fontSize:14, color: C.text }}>{dataSel}</h3>
          <table style={{ width:'100%', borderCollapse:'collapse' }}>
            <tbody>
              {horas.map(h=>{
                const ev = eventosData(dataSel).filter(a=>a.hora===h);
                const cli = ev.length ? clientes.find(c=>c.id===ev[0].clienteId) : null;
                return (
                  <tr key={h} style={{ borderBottom:`1px solid ${C.border}` }}>
                    <td style={{ padding:'10px 12px', width:70, color: C.textMid, fontSize:13, fontWeight:600, verticalAlign:'top' }}>{h}</td>
                    <td style={{ padding:'6px 12px', verticalAlign:'top' }}>
                      {ev.map(e=>(
                        <div key={e.id} style={{ background: (corTipo[e.tipo]||C.gold)+'22', borderLeft:`3px solid ${corTipo[e.tipo]||C.gold}`, borderRadius:6, padding:'6px 10px', marginBottom:4 }}>
                          <div style={{ fontWeight:700, fontSize:13, color: C.text }}>{e.desc}</div>
                          <div style={{ fontSize:11, color: C.textMid }}>{cli?.nome} | {e.tipo} | {e.durMin}min</div>
                        </div>
                      ))}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* SEMANAL */}
      {vista==='semanal' && (
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', minWidth:600 }}>
            <thead>
              <tr>
                <th style={{ padding:'8px 10px', borderBottom:`2px solid ${C.border}`, width:60, color: C.textMid, fontSize:11 }}>Hora</th>
                {semanaAtual().map(d=><th key={d} style={{ padding:'8px 10px', borderBottom:`2px solid ${C.border}`, fontSize:11, color: d===fmt(hoje)?C.gold:C.text, fontWeight: d===fmt(hoje)?800:600, background: d===fmt(hoje)?C.goldPale:'transparent', textAlign:'center' }}>{d}</th>)}
              </tr>
            </thead>
            <tbody>
              {horas.map(h=>(
                <tr key={h} style={{ borderBottom:`1px solid ${C.border}` }}>
                  <td style={{ padding:'8px 10px', color: C.textMid, fontSize:12, fontWeight:600 }}>{h}</td>
                  {semanaAtual().map(d=>{
                    const ev = agenda.filter(a=>a.data===d&&a.hora===h);
                    return <td key={d} style={{ padding:'6px 8px', verticalAlign:'top', minWidth:80, background: d===fmt(hoje)?C.goldPale+'55':'transparent' }}>
                      {ev.map(e=><div key={e.id} style={{ background:(corTipo[e.tipo]||C.gold)+'22', borderLeft:`2px solid ${corTipo[e.tipo]||C.gold}`, borderRadius:4, padding:'3px 6px', fontSize:11, marginBottom:2 }}>{e.desc}</div>)}
                    </td>;
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* MENSAL */}
      {vista==='mensal' && (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(7,1fr)', gap:4 }}>
          {['Dom','Seg','Ter','Qua','Qui','Sex','Sab'].map(d=>(
            <div key={d} style={{ padding:'8px 4px', textAlign:'center', fontSize:11, fontWeight:700, color: C.textMid, borderBottom:`2px solid ${C.border}` }}>{d}</div>
          ))}
          {(() => {
            const dias = mesAtual();
            const [dd,mm,yyyy] = dias[0].split('/');
            const primeiroDow = new Date(Number(yyyy),Number(mm)-1,1).getDay();
            const cells = [];
            for(let i=0;i<primeiroDow;i++) cells.push(<div key={'e'+i} />);
            dias.forEach(d=>{
              const ev = eventosData(d);
              cells.push(
                <div key={d} onClick={()=>{setDataSel(d);setVista('diaria');}} style={{ minHeight:70, border:`1px solid ${C.border}`, borderRadius:6, padding:4, cursor:'pointer', background: d===fmt(hoje)?C.goldPale:'#fff', transition:'background .1s' }}
                  onMouseOver={e=>e.currentTarget.style.background=C.goldPale} onMouseOut={e=>e.currentTarget.style.background=d===fmt(hoje)?C.goldPale:'#fff'}>
                  <div style={{ fontSize:12, fontWeight:700, color: d===fmt(hoje)?C.gold:C.text, marginBottom:3 }}>{d.split('/')[0]}</div>
                  {ev.slice(0,2).map(e=><div key={e.id} style={{ fontSize:10, background:(corTipo[e.tipo]||C.gold)+'22', borderRadius:3, padding:'1px 4px', marginBottom:2, overflow:'hidden', whiteSpace:'nowrap', textOverflow:'ellipsis' }}>{e.hora} {e.desc}</div>)}
                  {ev.length>2 && <div style={{ fontSize:10, color: C.textLight }}>+{ev.length-2} mais</div>}
                </div>
              );
            });
            return cells;
          })()}
        </div>
      )}

      {modal && (
        <Modal title="Novo Compromisso" onClose={()=>setModal(false)}>
          <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
            <Inp label="Data" type="date" value={form.data} onChange={v=>setForm(p=>({...p,data:fmt(new Date(v+'T00:00:00'))}))} />
            <Sel label="Hora" value={form.hora} onChange={v=>setForm(p=>({...p,hora:v}))} opts={horas} />
            <Sel label="Tipo" value={form.tipo} onChange={v=>setForm(p=>({...p,tipo:v}))} opts={tipos} />
            <Sel label="Cliente" value={form.clienteId} onChange={v=>setForm(p=>({...p,clienteId:v}))} opts={[{value:'',label:'Selecione...'},...clientes.map(c=>({value:String(c.id),label:c.nome}))]} />
            <Inp label="Descricao" value={form.desc} onChange={v=>setForm(p=>({...p,desc:v}))} />
            <Inp label="Duracao (min)" type="number" value={form.durMin} onChange={v=>setForm(p=>({...p,durMin:Number(v)}))} />
            <Btn onClick={salvar}>Salvar</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
};


// ── APP ROOT ──────────────────────────────────────────────────
export default function App() {
  const [pagina, setPagina] = useState('Dashboard');
  const [clientes, setClientes] = useState(CLIENTES_INI);
  const [os, setOs] = useState(OS_INI);
  const [agenda, setAgenda] = useState(AGENDA_INI);
  const [pedidos, setPedidos] = useState(PEDIDOS_INI);
  const [contasFixas, setContasFixas] = useState(CONTAS_FIXAS_INI);
  const [contasPagar, setContasPagar] = useState(CONTAS_PAGAR_INI);
  const [tarefas, setTarefas] = useState(TAREFAS_INI);
  const [conversas] = useState(CONVERSAS_INI);
  const [orcamentos, setOrcamentos] = useState(ORCAMENTOS_INI);
  const [briefings, setBriefings] = useState(BRIEFINGS_INI);
  const [menuAberto, setMenuAberto] = useState(true);

  const nav = [
    { label:'Dashboard', icone:'D' },
    { label:'Clientes', icone:'C' },
    { label:'Fluxo de Atendimento', icone:'F' },
    { label:'Consultoria Express', icone:'C' },
    { label:'Criacao e Dossie', icone:'B' },
    { label:'Orcamentos', icone:'O' },
    { label:'Financeiro', icone:'$' },
    { label:'Agenda', icone:'A' },
  ];

  const alertas = os.filter(o=>diasSemAtualizar(o.ultimaAtualizacao)>=14&&o.status!=='entregue').length;

  return (
    <div style={{ minHeight:'100vh', background: C.bg, fontFamily:"'Georgia', 'Times New Roman', serif", display:'flex' }}>
      {/* SIDEBAR */}
      <aside style={{ width: menuAberto?220:60, minHeight:'100vh', background:'#111', flexShrink:0, transition:'width .2s', display:'flex', flexDirection:'column' }}>
        {/* Logo */}
        <div style={{ padding: menuAberto?'24px 20px 16px':'16px 10px', borderBottom:'1px solid #2a2a2a', display:'flex', alignItems:'center', gap:12, justifyContent: menuAberto?'flex-start':'center' }}>
          <img src={`data:image/jpeg;base64,${LOGO_B64}`} alt="Das G" style={{ width:40, height:40, borderRadius:'50%', objectFit:'cover', flexShrink:0, border:'2px solid '+C.gold }} />
          {menuAberto && <div>
            <div style={{ fontSize:14, fontWeight:800, color:'#fff', letterSpacing:1 }}>Das G Digital</div>
            <div style={{ fontSize:10, color: C.gold, letterSpacing:.5 }}>Atelie de Alta Costura</div>
          </div>}
        </div>

        {/* Nav */}
        <nav style={{ flex:1, padding:'12px 0' }}>
          {nav.map(n=>{
            const ativo = pagina===n.label;
            const showAlerta = n.label==='Fluxo de Atendimento' && alertas>0;
            return (
              <button key={n.label} onClick={()=>setPagina(n.label)} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, padding: menuAberto?'11px 20px':'11px 0', justifyContent: menuAberto?'flex-start':'center', border:'none', background: ativo?C.gold:'transparent', color: ativo?'#111':'#ccc', cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight: ativo?700:400, transition:'background .15s', borderLeft: ativo?`3px solid #fff`:'3px solid transparent', position:'relative' }}
                onMouseOver={e=>!ativo&&(e.currentTarget.style.background='#222')} onMouseOut={e=>!ativo&&(e.currentTarget.style.background='transparent')}>
                <span style={{ fontSize:13, fontWeight:700, width:22, textAlign:'center', flexShrink:0 }}>{n.icone}</span>
                {menuAberto && <span>{n.label}</span>}
                {showAlerta && menuAberto && <span style={{ marginLeft:'auto', background: C.red, color:'#fff', borderRadius:'50%', width:18, height:18, display:'flex', alignItems:'center', justifyContent:'center', fontSize:10, fontWeight:800 }}>{alertas}</span>}
              </button>
            );
          })}
        </nav>

        {/* Toggle */}
        <button onClick={()=>setMenuAberto(!menuAberto)} style={{ padding:'12px', border:'none', background:'#222', color:'#888', cursor:'pointer', fontSize:16, fontFamily:'inherit' }}>{menuAberto?'<<':'>>'}</button>
      </aside>

      {/* MAIN */}
      <main style={{ flex:1, minWidth:0, display:'flex', flexDirection:'column', maxHeight:'100vh', overflow:'hidden' }}>
        {/* Header */}
        <header style={{ background:'#fff', borderBottom:`1px solid ${C.border}`, padding:'14px 28px', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <div>
            <h1 style={{ margin:0, fontSize:18, fontWeight:800, color: C.text, letterSpacing:.3 }}>{pagina}</h1>
            <div style={{ fontSize:11, color: C.textLight, marginTop:2 }}>{new Date().toLocaleDateString('pt-BR',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}</div>
          </div>
          <div style={{ display:'flex', gap:12, alignItems:'center' }}>
            {alertas>0 && (
              <div style={{ background: C.redPale, border:`1px solid ${C.red}`, borderRadius:8, padding:'6px 12px', fontSize:12, color: C.red, fontWeight:700, cursor:'pointer' }} onClick={()=>setPagina('Fluxo de Atendimento')}>
                {alertas} OS parada{alertas>1?'s':''}
              </div>
            )}
            <div style={{ fontSize:13, color: C.textMid }}>Juliana Pereira</div>
          </div>
        </header>

        {/* Conteudo */}
        <div style={{ flex:1, overflowY:'auto', padding:28 }}>
          {pagina==='Dashboard' && <Dashboard os={os} clientes={clientes} agenda={agenda} pedidos={pedidos} tarefas={tarefas} conversas={conversas} setTarefas={setTarefas} />}
          {pagina==='Clientes' && <Clientes clientes={clientes} os={os} setClientes={setClientes} />}
          {pagina==='Fluxo de Atendimento' && <FluxoAtendimento os={os} clientes={clientes} setOs={setOs} />}
          {pagina==='Consultoria Express' && <ConsultoriaEstilistaExpress clientes={clientes} briefings={briefings} setBriefings={setBriefings} os={os} setOs={setOs} />}
          {pagina==='Criacao e Dossie' && <BriefingDossie clientes={clientes} briefings={briefings} setBriefings={setBriefings} os={os} />}
          {pagina==='Orcamentos' && <Orcamentos clientes={clientes} orcamentos={orcamentos} setOrcamentos={setOrcamentos} os={os} setOs={setOs} printOrcamento={printOrcamento} />}
          {pagina==='Financeiro' && <Financeiro pedidos={pedidos} setPedidos={setPedidos} contasFixas={contasFixas} setContasFixas={setContasFixas} contasPagar={contasPagar} setContasPagar={setContasPagar} clientes={clientes} />}
          {pagina==='Agenda' && <Agenda agenda={agenda} setAgenda={setAgenda} clientes={clientes} os={os} />}
        </div>
      </main>
    </div>
  );
}


// ── TELA DE CONSULTORIA ESTILISTA EXPRESS ────────────────────
const ConsultoriaEstilistaExpress = ({ clientes, briefings, setBriefings, os, setOs }) => {
  const [clienteId, setClienteId] = useState('');
  const [osId, setOsId] = useState('');
  const [anotacoes, setAnotacoes] = useState({ estilo:'', referencias:'', tecidos:'', cores:'', restricoes:'', orcamento:'', silhueta:'', detalhes:'', livrePrincipal:'' });
  const [livreExtra, setLivreExtra] = useState('');
  const [linkZoom, setLinkZoom] = useState('');
  const [finalizado, setFinalizado] = useState(false);
  const [salvando, setSalvando] = useState(false);

  // Estado das subjanelas flutuantes
  const [janelaFotos, setJanelaFotos] = useState(false);
  const [janelaFormulario, setJanelaFormulario] = useState(false);
  const [janelaEscrita, setJanelaEscrita] = useState(false);

  const cli = clientes.find(c => c.id === Number(clienteId));
  const osAtual = os.find(o => o.id === osId);
  const briefingCli = briefings.find(b => b.clienteId === Number(clienteId));
  const osCliente = os.filter(o => o.clienteId === Number(clienteId));

  const wppLink = cli ? `https://wa.me/${cli.fone.replace(/\D/g,'')}` : '#';

  const finalizar = async () => {
    if (!clienteId) { alert('Selecione uma cliente'); return; }
    setSalvando(true);
    await new Promise(r => setTimeout(r, 600));

    // Salvar no briefing
    const resumo = Object.entries(anotacoes)
      .filter(([k,v]) => v)
      .map(([k,v]) => `${k.toUpperCase()}: ${v}`)
      .join('\n') + (livreExtra ? '\n\nNOTAS EXTRAS:\n' + livreExtra : '');

    setBriefings(prev => {
      const existe = prev.find(b => b.clienteId === Number(clienteId));
      const atualizado = {
        id: existe?.id || Date.now(),
        clienteId: Number(clienteId),
        respostas: {
          ...(existe?.respostas || {}),
          estilo: anotacoes.estilo,
          tecidos: anotacoes.tecidos,
          cores: anotacoes.cores,
          refs: anotacoes.referencias,
          corpo: anotacoes.restricoes,
          obs: anotacoes.detalhes,
        },
        dossie: existe?.dossie || '',
        status: 'pendente',
        anotacoesConsultoria: resumo,
        dataConsultoria: fmt(hoje),
      };
      if (existe) return prev.map(b => b.clienteId === Number(clienteId) ? atualizado : b);
      return [...prev, atualizado];
    });

    // Avancar OS para criacao
    if (osId) {
      setOs(prev => prev.map(o => o.id === osId
        ? { ...o, status: 'criacao', ultimaAtualizacao: new Date().toISOString().split('T')[0] }
        : o));
    }

    setSalvando(false);
    setFinalizado(true);
  };

  const campos = [
    { key:'estilo', label:'Estilo desejado', placeholder:'Romantico, moderno, classico...' },
    { key:'referencias', label:'Referencias e inspiracoes', placeholder:'Sites, fotos, marcas...' },
    { key:'tecidos', label:'Tecidos preferidos', placeholder:'Renda, tule, crepe, seda...' },
    { key:'cores', label:'Cores', placeholder:'Paleta de cores escolhida...' },
    { key:'restricoes', label:'Restricoes / corpo', placeholder:'Busto G, ombro, quadril...' },
    { key:'orcamento', label:'Orcamento confirmado', placeholder:'R$ ...' },
    { key:'silhueta', label:'Silhueta e modelagem', placeholder:'Sereia, evasê, princesa...' },
    { key:'detalhes', label:'Detalhes e acabamentos', placeholder:'Bordado, renda, recortes...' },
  ];

  if (finalizado) {
    return (
      <div style={{ textAlign:'center', padding:'60px 20px' }}>
        <div style={{ fontSize:48, marginBottom:16 }}>✓</div>
        <h2 style={{ color: C.green, fontSize:22, marginBottom:8 }}>Consultoria finalizada!</h2>
        <p style={{ color: C.textMid, fontSize:14, marginBottom:24 }}>Todas as anotacoes foram salvas no briefing da cliente.<br/>O status da OS foi avancado para <strong>Criacao</strong>.</p>
        <div style={{ display:'flex', gap:12, justifyContent:'center' }}>
          <Btn onClick={() => setFinalizado(false)} variant="ghost">Nova consultoria</Btn>
          <Btn onClick={() => { setFinalizado(false); setClienteId(''); setAnotacoes({ estilo:'', referencias:'', tecidos:'', cores:'', restricoes:'', orcamento:'', silhueta:'', detalhes:'', livrePrincipal:'' }); setLivreExtra(''); }}>Voltar</Btn>
        </div>
      </div>
    );
  }

  return (
    <div style={{ position:'relative', minHeight:'80vh' }}>
      {/* Cabecalho da sala */}
      <div style={{ background:'#111', borderRadius:10, padding:'14px 20px', marginBottom:16, display:'flex', gap:16, alignItems:'center', flexWrap:'wrap' }}>
        <div style={{ width:36, height:36, borderRadius:'50%', border:`2px solid ${C.gold}`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:16, fontWeight:800, color: C.gold, background:'#222', flexShrink:0 }}>
          {cli ? cli.nome[0] : 'E'}
        </div>
        <div style={{ flex:1, minWidth:180 }}>
          <Sel label="" value={clienteId} onChange={v => { setClienteId(v); setOsId(''); }} opts={[{value:'',label:'Selecione a cliente...'}, ...clientes.map(c=>({value:String(c.id),label:c.nome}))]} style={{ background:'#222', color:'#fff', border:'1px solid #444' }} />
        </div>
        {cli && osCliente.length > 0 && (
          <div style={{ flex:1, minWidth:160 }}>
            <Sel label="" value={osId} onChange={setOsId} opts={[{value:'',label:'Vincular OS...'}, ...osCliente.map(o=>({value:o.id,label:o.id+' - '+o.descricao.slice(0,25)}))]} style={{ background:'#222', color:'#fff', border:'1px solid #444' }} />
          </div>
        )}
        <div style={{ flex:2, minWidth:200 }}>
          <input value={linkZoom} onChange={e=>setLinkZoom(e.target.value)} placeholder="Cole aqui o link do Zoom / Meet / outro..." style={{ width:'100%', padding:'8px 12px', background:'#222', border:'1px solid #444', borderRadius:6, color:'#fff', fontSize:13, boxSizing:'border-box' }} />
        </div>
        {linkZoom && (
          <a href={linkZoom} target="_blank" rel="noreferrer" style={{ background: C.green, color:'#fff', padding:'8px 16px', borderRadius:6, fontSize:13, fontWeight:700, textDecoration:'none', whiteSpace:'nowrap' }}>Abrir Reuniao</a>
        )}
        {cli && (
          <a href={wppLink} target="_blank" rel="noreferrer" style={{ background:'#25D366', color:'#fff', padding:'8px 16px', borderRadius:6, fontSize:13, fontWeight:700, textDecoration:'none', whiteSpace:'nowrap' }}>WhatsApp</a>
        )}
      </div>

      {!clienteId && (
        <div style={{ textAlign:'center', padding:'60px 20px', color: C.textLight, fontSize:14 }}>Selecione uma cliente para comecar a consultoria</div>
      )}

      {clienteId && (
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
          {/* COLUNA ESQUERDA: Dados da cliente + preview briefing */}
          <div style={{ display:'flex', flexDirection:'column', gap:14 }}>

            {/* Card da cliente */}
            <Card style={{ borderTop:`3px solid ${C.gold}` }}>
              <div style={{ display:'flex', gap:12, alignItems:'flex-start', marginBottom:12 }}>
                <div style={{ width:56, height:56, borderRadius:'50%', background: C.goldPale, border:`2px solid ${C.gold}`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:22, fontWeight:800, color: C.gold, flexShrink:0, overflow:'hidden' }}>
                  {cli?.fotos?.length > 0
                    ? <img src={cli.fotos[0].url} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                    : cli?.nome[0]}
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:800, fontSize:16, color: C.text }}>{cli?.nome}</div>
                  <div style={{ fontSize:12, color: C.textMid }}>{cli?.papel} · {cli?.fone}</div>
                  {cli?.eventoData && <div style={{ fontSize:12, color: C.gold, marginTop:2 }}>Evento: {new Date(cli.eventoData+'T00:00:00').toLocaleDateString('pt-BR')}</div>}
                </div>
                <div style={{ display:'flex', gap:6 }}>
                  {cli?.fotos?.length > 0 && (
                    <button onClick={() => setJanelaFotos(!janelaFotos)} title="Ver fotos da cliente" style={{ background: janelaFotos ? C.gold : C.goldPale, color: janelaFotos ? '#fff' : C.gold, border:`1px solid ${C.gold}`, borderRadius:6, width:32, height:32, cursor:'pointer', fontSize:16, fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center' }}>
                      F
                    </button>
                  )}
                  {briefingCli && (
                    <button onClick={() => setJanelaFormulario(!janelaFormulario)} title="Ver formulario raio-x" style={{ background: janelaFormulario ? C.blue : C.bluePale, color: janelaFormulario ? '#fff' : C.blue, border:`1px solid ${C.blue}`, borderRadius:6, width:32, height:32, cursor:'pointer', fontSize:16, fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center' }}>
                      Q
                    </button>
                  )}
                  <button onClick={() => setJanelaEscrita(!janelaEscrita)} title="Abrir area de escrita expandida" style={{ background: janelaEscrita ? C.purple : C.purplePale, color: janelaEscrita ? '#fff' : C.purple, border:`1px solid ${C.purple}`, borderRadius:6, width:32, height:32, cursor:'pointer', fontSize:16, fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center' }}>
                      E
                    </button>
                </div>
              </div>

              {/* Medidas rapidas */}
              {cli?.medidas && Object.values(cli.medidas).some(v=>v) && (
                <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginTop:4 }}>
                  {Object.entries(cli.medidas).map(([k,v]) => v ? (
                    <span key={k} style={{ background: C.goldPale, color: C.gold, borderRadius:20, padding:'2px 10px', fontSize:11, fontWeight:700 }}>
                      {k}: {v}cm
                    </span>
                  ) : null)}
                </div>
              )}
            </Card>

            {/* Preview do briefing raio-x */}
            {briefingCli && (
              <Card style={{ borderLeft:`3px solid ${C.blue}` }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:10 }}>
                  <h4 style={{ margin:0, fontSize:13, color: C.blue, fontWeight:700 }}>Resumo do Formulario Raio-X</h4>
                  <Tag label={briefingCli.status||'pendente'} cor={C.blue} corPale={C.bluePale} small />
                </div>
                {Object.entries(briefingCli.respostas||{}).map(([k,v]) => v ? (
                  <div key={k} style={{ marginBottom:6 }}>
                    <span style={{ fontSize:10, fontWeight:700, color: C.textMid, textTransform:'uppercase' }}>{k}: </span>
                    <span style={{ fontSize:12, color: C.text }}>{v}</span>
                  </div>
                ) : null)}
                {briefingCli.dossie && (
                  <div style={{ marginTop:10, padding:'8px 12px', background: C.goldPale, borderRadius:6, borderLeft:`2px solid ${C.gold}` }}>
                    <div style={{ fontSize:10, fontWeight:700, color: C.gold, marginBottom:4 }}>PROPOSTA CRIATIVA</div>
                    <div style={{ fontSize:12, color: C.text, lineHeight:1.6 }}>{briefingCli.dossie}</div>
                  </div>
                )}
              </Card>
            )}

            {!briefingCli && (
              <Card style={{ textAlign:'center', padding:24, border:`2px dashed ${C.border}` }}>
                <p style={{ color: C.textLight, fontSize:13 }}>Cliente ainda nao preencheu o formulario raio-x.</p>
              </Card>
            )}

            {/* Anotacoes livres principais */}
            <Card>
              <h4 style={{ margin:'0 0 10px', fontSize:13, color: C.text, fontWeight:700 }}>Anotacoes livres</h4>
              <textarea
                value={anotacoes.livrePrincipal}
                onChange={e => setAnotacoes(p => ({ ...p, livrePrincipal: e.target.value }))}
                placeholder="Anote aqui tudo que surgir durante a conversa..."
                rows={6}
                style={{ width:'100%', padding:'10px', border:`1px solid ${C.border}`, borderRadius:8, fontSize:13, resize:'vertical', fontFamily:'inherit', lineHeight:1.6, boxSizing:'border-box', outline:'none' }}
                onFocus={e=>e.target.style.borderColor=C.gold} onBlur={e=>e.target.style.borderColor=C.border}
              />
            </Card>
          </div>

          {/* COLUNA DIREITA: Campos estruturados + finalizar */}
          <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
            <Card style={{ borderTop:`3px solid ${C.purple}` }}>
              <h4 style={{ margin:'0 0 14px', fontSize:13, color: C.purple, fontWeight:700 }}>Anotacoes da consultoria</h4>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {campos.map(({ key, label, placeholder }) => (
                  <div key={key} style={{ display:'flex', flexDirection:'column', gap:4 }}>
                    <label style={{ fontSize:10, fontWeight:700, color: C.textMid, textTransform:'uppercase', letterSpacing:.5 }}>{label}</label>
                    <input
                      value={anotacoes[key]}
                      onChange={e => setAnotacoes(p => ({ ...p, [key]: e.target.value }))}
                      placeholder={placeholder}
                      style={{ padding:'7px 10px', border:`1px solid ${C.border}`, borderRadius:6, fontSize:12, color: C.text, background:'#fff', outline:'none' }}
                      onFocus={e=>e.target.style.borderColor=C.gold} onBlur={e=>e.target.style.borderColor=C.border}
                    />
                  </div>
                ))}
              </div>
            </Card>

            {/* Proximo passo */}
            <Card style={{ background:'#111', border:'none' }}>
              <h4 style={{ margin:'0 0 8px', fontSize:13, color: C.gold, fontWeight:700 }}>Proximo passo apos finalizar</h4>
              <p style={{ color:'#aaa', fontSize:12, margin:'0 0 14px', lineHeight:1.6 }}>
                Ao finalizar esta consultoria:<br/>
                1. As anotacoes serao salvas no briefing da cliente<br/>
                2. A OS avancara para o status <strong style={{ color: C.gold }}>Criacao</strong><br/>
                3. O briefing ficara disponivel para a IA gerar o croqui e elaborar o dossie
              </p>
              <Btn onClick={finalizar} disabled={salvando || !clienteId} style={{ width:'100%', padding:'12px', fontSize:14, justifyContent:'center' }}>
                {salvando ? 'Salvando...' : 'Finalizar Consultoria'}
              </Btn>
            </Card>
          </div>
        </div>
      )}

      {/* ── SUBJANELAS FLUTUANTES ── */}

      {/* Fotos da cliente */}
      {janelaFotos && cli && (
        <div style={{ position:'fixed', top:'10vh', right:20, width:340, maxHeight:'70vh', background:'#fff', borderRadius:12, boxShadow:'0 8px 40px rgba(0,0,0,.22)', zIndex:900, overflow:'hidden', border:`1px solid ${C.border}` }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'12px 16px', borderBottom:`1px solid ${C.border}`, background: C.goldPale }}>
            <span style={{ fontSize:13, fontWeight:700, color: C.gold }}>Fotos — {cli.nome}</span>
            <button onClick={() => setJanelaFotos(false)} style={{ border:'none', background:'none', cursor:'pointer', fontSize:18, color: C.textLight }}>x</button>
          </div>
          <div style={{ padding:12, overflowY:'auto', maxHeight:'calc(70vh - 50px)' }}>
            {cli.fotos?.length > 0 ? (
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
                {cli.fotos.map((f,i) => (
                  <img key={i} src={f.url} alt="" style={{ width:'100%', height:140, objectFit:'cover', borderRadius:8, border:`1px solid ${C.border}` }} />
                ))}
              </div>
            ) : <p style={{ color: C.textLight, fontSize:12, textAlign:'center', padding:20 }}>Nenhuma foto cadastrada.</p>}
          </div>
        </div>
      )}

      {/* Formulario completo */}
      {janelaFormulario && briefingCli && (
        <div style={{ position:'fixed', top:'10vh', left:20, width:380, maxHeight:'75vh', background:'#fff', borderRadius:12, boxShadow:'0 8px 40px rgba(0,0,0,.22)', zIndex:900, overflow:'hidden', border:`1px solid ${C.border}` }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'12px 16px', borderBottom:`1px solid ${C.border}`, background: C.bluePale }}>
            <span style={{ fontSize:13, fontWeight:700, color: C.blue }}>Formulario Raio-X Completo</span>
            <button onClick={() => setJanelaFormulario(false)} style={{ border:'none', background:'none', cursor:'pointer', fontSize:18, color: C.textLight }}>x</button>
          </div>
          <div style={{ padding:16, overflowY:'auto', maxHeight:'calc(75vh - 52px)' }}>
            {Object.entries(briefingCli.respostas||{}).map(([k,v]) => v ? (
              <div key={k} style={{ marginBottom:12, paddingBottom:12, borderBottom:`1px solid ${C.border}` }}>
                <div style={{ fontSize:10, fontWeight:700, color: C.textMid, textTransform:'uppercase', letterSpacing:.5, marginBottom:4 }}>{k}</div>
                <div style={{ fontSize:13, color: C.text, lineHeight:1.6 }}>{v}</div>
              </div>
            ) : null)}
            {briefingCli.dossie && (
              <div style={{ background: C.goldPale, borderRadius:8, padding:12, marginTop:8 }}>
                <div style={{ fontSize:10, fontWeight:700, color: C.gold, marginBottom:6 }}>PROPOSTA CRIATIVA</div>
                <div style={{ fontSize:12, color: C.text, lineHeight:1.7 }}>{briefingCli.dossie}</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Area de escrita expandida */}
      {janelaEscrita && (
        <div style={{ position:'fixed', bottom:20, left:'50%', transform:'translateX(-50%)', width:'min(700px, 90vw)', background:'#fff', borderRadius:12, boxShadow:'0 8px 40px rgba(0,0,0,.22)', zIndex:900, border:`1px solid ${C.border}` }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'12px 16px', borderBottom:`1px solid ${C.border}`, background: C.purplePale }}>
            <span style={{ fontSize:13, fontWeight:700, color: C.purple }}>Area de escrita expandida</span>
            <button onClick={() => setJanelaEscrita(false)} style={{ border:'none', background:'none', cursor:'pointer', fontSize:18, color: C.textLight }}>x</button>
          </div>
          <div style={{ padding:12 }}>
            <textarea
              value={livreExtra}
              onChange={e => setLivreExtra(e.target.value)}
              placeholder="Espaco ampliado para anotacoes detalhadas durante o atendimento — inspiracoes, referencias trocadas no WhatsApp, decisoes tomadas durante a reuniao..."
              rows={8}
              autoFocus
              style={{ width:'100%', padding:'12px', border:`1px solid ${C.border}`, borderRadius:8, fontSize:13, resize:'vertical', fontFamily:'inherit', lineHeight:1.7, boxSizing:'border-box', outline:'none' }}
              onFocus={e=>e.target.style.borderColor=C.purple} onBlur={e=>e.target.style.borderColor=C.border}
            />
            <div style={{ fontSize:11, color: C.textLight, marginTop:6 }}>Estas anotacoes serao anexadas ao briefing ao finalizar a consultoria.</div>
          </div>
        </div>
      )}
    </div>
  );
};

